// Unit 23 — Sin Embargo
// Advanced Connectors

export default {n:23,lang:"es",srcLang:"en",track:"v2",title:"Sin Embargo",sub:"Advanced Connectors",icon:"🔀",level:"B1.4",color:"#7B5EE8",lessons:[
  {id:"esp23l1",title:"Aunque llueve...",icon:"🌧️",xp:20,board:true,steps:[
        {type:"intro",title:"Aunque llueve...",desc:"Learn to express contrast with aunque followed by the indicative mood, used when the obstacle is a known fact.",goals:["Use aunque + indicative for known facts","Express 'even though' in real situations","Combine aunque clauses with present and past tenses"]},
        {type:"teach",trg:"aunque",src:"even though, although",pos:"conj",gender:null,phonetic:"ah-OON-keh",note:"Aunque + indicative = the situation IS real/true.\nAunque + subjunctive = hypothetical (next lesson).",example:"A: Aunque llueve, vamos al parque.\nB: Buena idea. Me gusta la lluvia.\nA: A mi tambien. Aunque hace frio, es bonito.\nB: Si, la lluvia tiene su encanto.",exampleSrc:"A: Even though it's raining, we're going to the park.\nB: Good idea. I like the rain.\nA: Me too. Even though it's cold, it's beautiful.\nB: Yes, the rain has its charm.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"teach",trg:"aunque llueve",src:"even though it's raining",pos:"intj",gender:null,phonetic:"ah-OON-keh YWEH-beh",note:"Indicative llueve because the rain is a fact right now.",example:"A: ¿Salimos hoy?\nB: Aunque llueve, podemos ir al museo.\nA: Perfecto. Llevo el paraguas.\nB: Yo tambien. Aunque llueve mucho, merece la pena.",exampleSrc:"A: Shall we go out today?\nB: Even though it's raining, we can go to the museum.\nA: Perfect. I'll bring the umbrella.\nB: Me too. Even though it's raining a lot, it's worth it.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"aunque estoy cansado",src:"even though I'm tired",pos:"intj",gender:null,phonetic:"ah-OON-keh ehs-TOY kahn-SAH-doh",note:"Estoy = indicative. The tiredness is real, not hypothetical.",example:"A: ¿Vienes a la fiesta?\nB: Aunque estoy cansado, voy a ir.\nA: Genial. No te arrepentiras.\nB: Eso espero. Aunque tengo sueno, quiero verte.\nA: Nos vemos a las nueve entonces.",exampleSrc:"A: Are you coming to the party?\nB: Even though I'm tired, I'm going to go.\nA: Great. You won't regret it.\nB: I hope so. Even though I'm sleepy, I want to see you.\nA: See you at nine then.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"aunque no tengo tiempo",src:"even though I don't have time",pos:"intj",gender:null,phonetic:"ah-OON-keh noh TEHN-goh TYEHM-poh",note:"No tengo = indicative. The lack of time is a real fact.",example:"A: ¿Puedes ayudarme con el proyecto?\nB: Aunque no tengo mucho tiempo, te ayudo.\nA: Muchas gracias. Es solo media hora.\nB: No hay problema. Aunque estoy ocupado, es importante.",exampleSrc:"A: Can you help me with the project?\nB: Even though I don't have much time, I'll help you.\nA: Thank you very much. It's only half an hour.\nB: No problem. Even though I'm busy, it's important.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Aunque + Indicative vs Subjunctive",deepDive:"The indicative signals that the speaker KNOWS the obstacle is true. 'Aunque estoy cansado, voy' means I acknowledge my tiredness as fact but go anyway. Compare English: 'even though' (fact) vs 'even if' (hypothetical).",text:"Aunque has TWO modes:\n1. Aunque + INDICATIVE = real fact\n  Aunque llueve... (it IS raining)\n2. Aunque + SUBJUNCTIVE = hypothetical\n  Aunque llueva... (even IF it rains)\n\nThis lesson: indicative only.\nNext lesson: subjunctive."},
        {type:"mc",q:"'Aunque _____ frio, vamos a la playa.' (It IS cold, fact)",opts:["hace","haga","haria","hizo"],ans:"hace",hint:"Indicative for a known fact about the weather right now."},
        {type:"fb",opts:["tengo","tenga","tenia","tendria"],hint:"The lack of money is a current reality, so use indicative present.",s:"Aunque no {1} dinero, quiero viajar.",a:["tengo"]},
        {type:"teach",trg:"aunque no me gusta",src:"even though I don't like it",pos:"intj",gender:null,phonetic:"ah-OON-keh noh meh GOOS-tah",note:"No me gusta = indicative. The dislike is a real feeling.",example:"A: ¿Comes verduras?\nB: Aunque no me gustan mucho, las como.\nA: Es importante para la salud.\nB: Lo se. Aunque prefiero la carne, intento comer equilibrado.\nA: Yo tambien. Aunque no me gusta el brocoli, lo como.",exampleSrc:"A: Do you eat vegetables?\nB: Even though I don't like them much, I eat them.\nA: It's important for health.\nB: I know. Even though I prefer meat, I try to eat balanced.\nA: Me too. Even though I don't like broccoli, I eat it.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"Which sentence uses aunque with a REAL situation?",opts:["Aunque llueva, saldre a correr.","Aunque llueve, salgo a correr.","Aunque lloviera, saldria a correr.","Aunque va a llover, me quedo."],ans:"Aunque llueve, salgo a correr.",hint:"Look for the indicative present tense after ___."},
        {type:"fb",opts:["esta","este","estuviera","estaria"],hint:"The distance is a known fact about the office location.",s:"Aunque {1} lejos, voy andando al trabajo.",a:["esta"]},
        {type:"mc",q:"'Aunque mi jefe es estricto, me gusta mi trabajo.' What does aunque express here?",opts:["A condition for liking the job","A hypothetical: if the boss were strict","A real contrast: the boss IS strict but I like my job","A cause of liking the job"],ans:"A real contrast: the boss IS strict but I like my job",hint:"The indicative 'es' tells you the ___ness is a known fact."},
        {type:"teach",trg:"aunque ya lo sabia",src:"even though I already knew it",pos:"intj",gender:null,phonetic:"ah-OON-keh yah loh sah-BEE-ah",note:"Sabia = imperfect indicative. Past fact, not hypothetical.",example:"A: ¿Te enteraste de la noticia?\nB: Aunque ya lo sabia, me sorprendio.\nA: A mi tambien. Aunque esperaba el cambio, fue repentino.\nB: Si. Aunque lo lei ayer, no lo creia.\nA: Es dificil de aceptar.",exampleSrc:"A: Did you hear the news?\nB: Even though I already knew, it surprised me.\nA: Me too. Even though I expected the change, it was sudden.\nB: Yes. Even though I read it yesterday, I didn't believe it.\nA: It's hard to accept.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"'Aunque _____ mucho, no aprobo el examen.' (She DID study a lot, past fact)",opts:["estudiaba","estudiara","estudie","estudio"],ans:"estudio",hint:"A past completed fact calls for preterite indicative after aunque."},
        {type:"fb",opts:["estaba","estuviera","este","estuvo"],hint:"An ongoing past state (she was sick at the time) uses the imperfect.",s:"Aunque {1} enferma, fue a trabajar.",a:["estaba"]},
        {type:"match",pairs:[
          {trg:"Aunque llueve, salgo.",src:"Even though it's raining, I go out."},
          {trg:"Aunque no tengo hambre, como.",src:"Even though I'm not hungry, I eat."},
          {trg:"Aunque estaba cansada, trabajo.",src:"Even though she was tired, she worked."},
          {trg:"Aunque es caro, lo compro.",src:"Even though it's expensive, I buy it."}
        ]},
        {type:"drag_fill",hint:"Both verbs are indicative present. The limited Spanish is a fact.",s:"Aunque no {1} bien espanol, {2} comunicarme con la gente.",blanks:{"1":"hablo","2":"puedo"},pool:["hablo","puedo","hable","podria","hablar","poder"]},
        {type:"mc",q:"Choose the correct aunque sentence for: 'Even though we arrived late, they let us in.'",opts:["Aunque llegamos tarde, nos dejaron entrar.","Aunque llegaramos tarde, nos dejaron entrar.","Aunque lleguemos tarde, nos dejan entrar.","Aunque llegariamos tarde, nos dejaron entrar."],ans:"Aunque llegamos tarde, nos dejaron entrar.",hint:"Both events actually happened in the past. Use preterite indicative."},
        {type:"fb",opts:["sabe","sepa","supiera","sabria"],hint:"His limited knowledge is a real fact in the present.",s:"Aunque {1} poco espanol, siempre intenta hablar.",a:["sabe"]}
  ]},
  {id:"esp23l2",title:"Aunque llueva...",icon:"🌦️",xp:20,board:true,steps:[
        {type:"intro",title:"Aunque llueva...",desc:"Master aunque + subjunctive for hypothetical or conceded situations. 'Even if it rains, I'll go out.'",goals:["Distinguish aunque + indicative from aunque + subjunctive","Use subjunctive for hypothetical concessions","Switch between 'even though' (fact) and 'even if' (possibility)"]},
        {type:"teach",trg:"aunque llueva",src:"even if it rains",pos:"intj",gender:null,phonetic:"ah-OON-keh YWEH-bah",note:"Llueva = subjunctive. We don't know if it will rain.\nCompare: aunque llueve (it IS raining, fact).",example:"A: ¿Vamos manana a la playa?\nB: Si, aunque llueva, iremos.\nA: ¿De verdad? ¿Con lluvia?\nB: Si. Aunque haga frio, sera divertido.\nA: Vale, llevo la chaqueta por si acaso.",exampleSrc:"A: Shall we go to the beach tomorrow?\nB: Yes, even if it rains, we'll go.\nA: Really? With rain?\nB: Yes. Even if it's cold, it'll be fun.\nA: Okay, I'll bring a jacket just in case.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"aunque no quiera",src:"even if he/she doesn't want to",pos:"intj",gender:null,phonetic:"ah-OON-keh noh KYEH-rah",note:"Quiera = subjunctive of querer. His desire is uncertain.",example:"A: Carlos tiene que ir al medico.\nB: Aunque no quiera, tiene que ir.\nA: Es verdad. Aunque le de miedo, es necesario.\nB: Podemos acompanarlo.\nA: Buena idea. Aunque no quiera compania, vamos.",exampleSrc:"A: Carlos has to go to the doctor.\nB: Even if he doesn't want to, he has to go.\nA: That's true. Even if it scares him, it's necessary.\nB: We can go with him.\nA: Good idea. Even if he doesn't want company, let's go.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Aunque: Fact vs Hypothesis",deepDive:"In English, 'even though' signals fact and 'even if' signals hypothesis, but many speakers blur the distinction. Spanish forces you to choose: indicative or subjunctive. This is one of the clearest examples of how Spanish grammar encodes certainty vs uncertainty.",text:"The KEY distinction:\n\nAunque + INDICATIVE = I KNOW it's true\n  Aunque llueve... (it's raining now)\n  Aunque no tiene dinero... (he has no money)\n\nAunque + SUBJUNCTIVE = I DON'T KNOW or DON'T CARE\n  Aunque llueva... (it might rain)\n  Aunque no tenga dinero... (even if he has none)"},
        {type:"mc",q:"'Even if they don't agree, we'll do it.' Which is correct?",opts:["Aunque no esten de acuerdo, lo haremos.","Aunque no estan de acuerdo, lo haremos.","Aunque no estaban de acuerdo, lo haremos.","Aunque no estarian de acuerdo, lo haremos."],ans:"Aunque no esten de acuerdo, lo haremos.",hint:"Their agreement or disagreement is hypothetical, not confirmed."},
        {type:"fb",opts:["sea","es","seria","fue"],hint:"The difficulty is hypothetical: we don't know yet how hard it is.",s:"Aunque {1} dificil, lo voy a intentar.",a:["sea"]},
        {type:"teach",trg:"aunque me cueste",src:"even if it's hard for me",pos:"intj",gender:null,phonetic:"ah-OON-keh meh KWEHS-teh",note:"Cueste = subjunctive of costar. The difficulty is anticipated.",example:"A: ¿Vas a correr el maraton?\nB: Si, aunque me cueste mucho.\nA: Yo tambien. Aunque no termine, quiero participar.\nB: Eso es lo importante. Aunque sea duro, vale la pena.\nA: Nos apoyamos mutuamente.",exampleSrc:"A: Are you going to run the marathon?\nB: Yes, even if it's hard for me.\nA: Me too. Even if I don't finish, I want to participate.\nB: That's what matters. Even if it's tough, it's worth it.\nA: We'll support each other.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"Which sentence treats the situation as a KNOWN FACT?",opts:["Aunque sea caro, lo comprare.","Aunque es caro, lo compro.","Aunque fuera caro, lo compraria.","Aunque cueste mucho, lo quiero."],ans:"Aunque es caro, lo compro.",hint:"The indicative after ___ signals a confirmed reality."},
        {type:"drag_fill",hint:"Both clauses are hypothetical concessions about the future visit.",s:"Aunque no {1} tiempo, aunque {2} lejos, ire a verte.",blanks:{"1":"tenga","2":"vivas"},pool:["tenga","vivas","tengo","vives","tendria","viviras"]},
        {type:"fb",opts:["insistas","insistes","insistias","insistirias"],hint:"Whether they insist is hypothetical, so use present subjunctive.",s:"Aunque {1} mucho, no voy a cambiar de opinion.",a:["insistas"]},
        {type:"mc",q:"'Aunque _____ manana, iremos de excursion.' Fill in for 'even if it snows'.",opts:["nevara","nieva","nieve","nevaria"],ans:"nieve",hint:"Snowfall tomorrow is a possibility, not a fact. Use subjunctive."},
        {type:"teach",trg:"aunque no lo creas",src:"even if you don't believe it / believe it or not",pos:"intj",gender:null,phonetic:"ah-OON-keh noh loh KREH-ahs",note:"Creas = subjunctive. A set phrase meaning 'believe it or not'.",example:"A: Aunque no lo creas, he aprendido a cocinar.\nB: ¿De verdad? ¡No me lo creo!\nA: Es cierto. Aunque parezca imposible, hago paella.\nB: Aunque no lo crea, quiero probarlo.\nA: Ven a cenar el sabado.",exampleSrc:"A: Believe it or not, I've learned to cook.\nB: Really? I don't believe it!\nA: It's true. Even if it seems impossible, I make paella.\nB: Even though I don't believe it, I want to try it.\nA: Come to dinner on Saturday.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"match",pairs:[
          {trg:"Aunque llueva",src:"Even if it rains"},
          {trg:"Aunque llueve",src:"Even though it's raining"},
          {trg:"Aunque sea dificil",src:"Even if it's difficult"},
          {trg:"Aunque es dificil",src:"Even though it's difficult"}
        ]},
        {type:"mc",q:"Your friend is definitely sick but going to work. Which is correct?",opts:["Aunque sea enfermo, va a trabajar.","Aunque este enfermo, va a trabajar.","Aunque estuviera enfermo, iria a trabajar.","Aunque esta enfermo, va a trabajar."],ans:"Aunque esta enfermo, va a trabajar.",hint:"The illness is a confirmed fact, not a hypothesis."},
        {type:"drag_fill",hint:"Both are conceded possibilities before the exam. Use subjunctive.",s:"Aunque {1} poco, aunque no {2} todo, voy a hacer el examen.",blanks:{"1":"haya estudiado","2":"sepa"},pool:["haya estudiado","sepa","he estudiado","se","estudiara","supiera"]},
        {type:"fb",opts:["esten","estan","estuvieran","estarian"],hint:"We're conceding a possible state, not confirming they ARE tired.",s:"Aunque {1} cansados, siguen trabajando.",a:["esten"]},
        {type:"mc",q:"Translate: 'Even if you don't understand everything, keep reading.'",opts:["Aunque no entiendas todo, sigue leyendo.","Aunque no entiendes todo, sigue leyendo.","Aunque no entendieras todo, sigue leyendo.","Aunque no entenderas todo, sigue leyendo."],ans:"Aunque no entiendas todo, sigue leyendo.",hint:"The understanding level is hypothetical. Subjunctive + imperative."},
        {type:"fb",opts:["sea","es","seria","fue"],hint:"The difficulty of the path ahead is hypothetical. Subjunctive needed.",s:"Aunque {1} dificil el camino, no me rendire.",a:["sea"]}
  ]},
  {id:"esp23l3",title:"Sin embargo...",icon:"⚖️",xp:20,board:true,steps:[
        {type:"intro",title:"Sin embargo...",desc:"Learn formal contrast connectors used in writing and formal speech: sin embargo, no obstante, en cambio, por el contrario, mientras que.",goals:["Use sin embargo and no obstante for 'however/nevertheless'","Use en cambio and por el contrario for 'on the other hand'","Use mientras que for 'whereas'"]},
        {type:"teach",trg:"sin embargo",src:"however, nevertheless",pos:"conj",gender:null,phonetic:"seen ehm-BAHR-goh",note:"The most common formal contrast connector.\nAlways introduces the contrasting idea.",example:"A: El proyecto tiene problemas. Sin embargo, podemos solucionarlos.\nB: Estoy de acuerdo. Los plazos son cortos.\nA: Sin embargo, el equipo es muy competente.\nB: Es verdad. Sin embargo, necesitamos mas recursos.\nA: Hablare con la directora.",exampleSrc:"A: The project has problems. However, we can solve them.\nB: I agree. The deadlines are tight.\nA: However, the team is very competent.\nB: That's true. However, we need more resources.\nA: I'll talk to the director.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"teach",trg:"no obstante",src:"nevertheless, notwithstanding",pos:"intj",gender:null,phonetic:"noh ohb-STAHN-teh",note:"More formal than sin embargo.\nUsed in academic and journalistic writing.",example:"A: La economia esta en crisis.\nB: No obstante, algunas empresas crecen.\nA: Es cierto. No obstante, el desempleo sube.\nB: Los gobiernos deben actuar. No obstante, es complicado.\nA: Hay que buscar soluciones creativas.",exampleSrc:"A: The economy is in crisis.\nB: Nevertheless, some companies are growing.\nA: That's true. Nevertheless, unemployment is rising.\nB: Governments must act. Nevertheless, it's complicated.\nA: We need to look for creative solutions.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"en cambio",src:"on the other hand, instead",pos:"intj",gender:null,phonetic:"ehn KAHM-byoh",note:"Highlights a contrast between two subjects.\nSimilar to 'in contrast' or 'instead'.",example:"A: Maria estudia medicina. En cambio, su hermano estudia arte.\nB: Son muy diferentes.\nA: Si. Ella es muy seria. En cambio, el es muy creativo.\nB: En cambio, tienen algo en comun: los dos son trabajadores.\nA: Eso es verdad.",exampleSrc:"A: Maria studies medicine. On the other hand, her brother studies art.\nB: They're very different.\nA: Yes. She's very serious. On the other hand, he's very creative.\nB: On the other hand, they have something in common: both are hardworking.\nA: That's true.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"mientras que",src:"whereas, while",pos:"intj",gender:null,phonetic:"MYEHN-trahs keh",note:"Connects two contrasting facts in the same sentence.\nAlways compares two parallel situations.",example:"A: ¿Hay diferencias entre el norte y el sur?\nB: El norte es mas industrial, mientras que el sur es agricola.\nA: Mientras que en Madrid llueve poco, en el norte llueve mucho.\nB: Si. Mientras que el sur tiene calor, el norte es mas fresco.\nA: Espana es muy diversa.",exampleSrc:"A: Are there differences between the north and south?\nB: The north is more industrial, whereas the south is agricultural.\nA: Whereas in Madrid it rains little, in the north it rains a lot.\nB: Yes. While the south is hot, the north is cooler.\nA: Spain is very diverse.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Formal Contrast Connectors",deepDive:"Sin embargo and no obstante are near-synonyms and often interchangeable. The subtle difference: sin embargo is more common in everyday formal language, while no obstante feels more elevated and is preferred in legal or academic texts.",text:"From least to most formal:\n1. Pero (but) = everyday speech\n2. Sin embargo (however) = formal speech/writing\n3. No obstante (nevertheless) = academic/legal\n4. En cambio (on the other hand) = comparing two things\n5. Mientras que (whereas) = comparing within one sentence\n6. Por el contrario (on the contrary) = correcting a claim"},
        {type:"mc",q:"'El restaurante es caro. _____, la comida es excelente.' Choose the best connector.",opts:["Sin embargo","Mientras que","En cambio","Porque"],ans:"Sin embargo",hint:"You need a word meaning 'however' to contrast price with quality."},
        {type:"fb",opts:["No obstante","En cambio","Mientras que","Por eso"],hint:"Both cities share the quality. You need 'nevertheless' to add nuance.",s:"Madrid es una ciudad grande. {1}, Barcelona tambien lo es.",a:["No obstante"]},
        {type:"mc",q:"'Mi padre prefiere el campo, _____ mi madre prefiere la ciudad.' Which connector compares the two preferences?",opts:["sin embargo","mientras que","por eso","no obstante"],ans:"mientras que",hint:"You're comparing two people's preferences in the same sentence."},
        {type:"teach",trg:"por el contrario",src:"on the contrary",pos:"intj",gender:null,phonetic:"pohr ehl kohn-TRAH-ryoh",note:"Used to directly contradict a previous statement.\nStronger than sin embargo.",example:"A: Dicen que el espanol es facil.\nB: Por el contrario, tiene una gramatica compleja.\nA: ¿De verdad? Yo pensaba que era sencillo.\nB: Por el contrario, el subjuntivo es muy dificil.\nA: Entonces tengo mucho que aprender.",exampleSrc:"A: They say Spanish is easy.\nB: On the contrary, it has complex grammar.\nA: Really? I thought it was simple.\nB: On the contrary, the subjunctive is very difficult.\nA: Then I have a lot to learn.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"drag_fill",hint:"First blank compares two regions. Second blank adds a contrasting point.",s:"El norte es frio, {1} el sur es calido. {2}, ambas regiones son hermosas.",blanks:{"1":"mientras que","2":"Sin embargo"},pool:["mientras que","Sin embargo","En cambio","No obstante","Porque","Por eso"]},
        {type:"match",pairs:[{trg:"sin embargo",src:"however"},{trg:"no obstante",src:"nevertheless"},{trg:"en cambio",src:"on the other hand"},{trg:"mientras que",src:"whereas"},{trg:"por el contrario",src:"on the contrary"}]},
        {type:"mc",q:"Which connector would you use to directly CONTRADICT someone's claim?",opts:["Mientras que","Sin embargo","Por el contrario","En cambio"],ans:"Por el contrario",hint:"This connector corrects or opposes what was just said."},
        {type:"fb",opts:["Sin embargo","Mientras que","En cambio","Porque"],hint:"You need 'however' to contrast cold weather with enjoyment.",s:"El invierno es frio. {1}, mucha gente disfruta de la nieve.",a:["Sin embargo"]},
        {type:"drag_fill",hint:"First: comparing two work situations. Second: adding a shared positive despite the difference.",s:"Ana trabaja en una oficina, {1} su marido trabaja en casa. {2}, los dos ganan bien.",blanks:{"1":"mientras que","2":"No obstante"},pool:["mientras que","No obstante","En cambio","Por eso","Sin embargo","Porque"]},
        {type:"mc",q:"Which connector means 'on the contrary' and is used to directly OPPOSE a previous statement?",opts:["Mientras que","Sin embargo","En cambio","Por el contrario"],ans:"Por el contrario",hint:"This connector corrects or negates what was just claimed."},
        {type:"fb",opts:["Por el contrario","Sin embargo","En cambio","Mientras que"],hint:"You're directly contradicting the idea that the movie was boring.",s:"La pelicula no fue aburrida. {1}, fue muy emocionante.",a:["Por el contrario"]},
        {type:"mc",q:"'Juan habla tres idiomas. _____, su hermana habla cinco.' Which connector highlights the contrast between the two siblings?",opts:["En cambio","Por lo tanto","Asi que","Ya que"],ans:"En cambio",hint:"You're comparing two people's abilities. 'On the other hand' fits."}
  ]},
  {id:"esp23l4",title:"Puesto que...",icon:"🔍",xp:20,board:true,steps:[
        {type:"intro",title:"Puesto que...",desc:"Expand your causal vocabulary beyond porque with formal cause connectors: puesto que, ya que, dado que, and como.",goals:["Use puesto que, ya que, dado que for 'since/given that'","Use como at the beginning of sentences for 'since'","Choose the right formality level for each context"]},
        {type:"teach",trg:"puesto que",src:"since, given that",pos:"intj",gender:null,phonetic:"PWEHS-toh keh",note:"Formal alternative to porque.\nOften used in meetings, reports, and arguments.",example:"A: Puesto que tenemos poco tiempo, empecemos.\nB: De acuerdo. Puesto que todos estan aqui, podemos votar.\nA: Perfecto. Puesto que hay mayoria, la decision es valida.\nB: Bien. Puesto que estamos de acuerdo, pasemos al siguiente punto.\nA: Continuemos.",exampleSrc:"A: Since we have little time, let's start.\nB: Agreed. Since everyone is here, we can vote.\nA: Perfect. Since there's a majority, the decision is valid.\nB: Good. Since we agree, let's move to the next point.\nA: Let's continue.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"ya que",src:"since, seeing that",pos:"intj",gender:null,phonetic:"yah keh",note:"Slightly less formal than puesto que.\nCommon in both speech and writing.",example:"A: Ya que estas aqui, ¿me ayudas?\nB: Claro. Ya que tengo tiempo libre, con mucho gusto.\nA: Gracias. Ya que sabes de informatica, mira esto.\nB: A ver... Ya que el problema es el wifi, reinicia el router.\nA: ¡Funciona!",exampleSrc:"A: Since you're here, can you help me?\nB: Of course. Since I have free time, gladly.\nA: Thanks. Since you know about computers, look at this.\nB: Let me see... Since the problem is the wifi, restart the router.\nA: It works!",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"dado que",src:"given that",pos:"intj",gender:null,phonetic:"DAH-doh keh",note:"Very formal. Used in academic, legal, and business contexts.\nPresents facts as established premises.",example:"A: Dado que los precios han subido, debemos ahorrar.\nB: Tienes razon. Dado que la situacion es dificil, hay que planificar.\nA: Dado que no podemos viajar, vacaciones en casa.\nB: No esta mal. Dado que tenemos jardin, podemos disfrutar.\nA: Eso es ser positivo.",exampleSrc:"A: Given that prices have gone up, we should save.\nB: You're right. Given that the situation is difficult, we need to plan.\nA: Given that we can't travel, staycation.\nB: Not bad. Given that we have a garden, we can enjoy.\nA: That's being positive.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"como",src:"since (at start of sentence)",pos:"conj",gender:null,phonetic:"KOH-moh",note:"ONLY works at the START of a sentence.\n'Como' meaning 'since' cannot go in the middle.",example:"A: Como hace buen tiempo, vamos al parque.\nB: Buena idea. Como es sabado, no hay prisa.\nA: Como los ninos no tienen clase, pueden venir.\nB: Perfecto. Como tenemos comida, hacemos un picnic.\nA: ¡Que plan tan bueno!",exampleSrc:"A: Since the weather is nice, let's go to the park.\nB: Good idea. Since it's Saturday, there's no rush.\nA: Since the kids don't have class, they can come.\nB: Perfect. Since we have food, let's have a picnic.\nA: What a great plan!",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"tip",title:"Cause Connectors: Formality Scale",deepDive:"A key difference: como MUST start the sentence. 'Vamos al parque como hace sol' sounds wrong. But 'Como hace sol, vamos al parque' is natural. The other connectors (ya que, puesto que, dado que) can go at the beginning or middle of a sentence.",text:"From informal to formal:\n1. Porque (because) = everyday, goes AFTER the result\n2. Como (since) = everyday, goes BEFORE the result\n3. Ya que (since) = semi-formal, flexible position\n4. Puesto que (since/given that) = formal\n5. Dado que (given that) = very formal, academic\n\nAll mean roughly the same but set different tones."},
        {type:"mc",q:"'_____ no hay clase, podemos dormir hasta tarde.' Which fits at the START of this sentence?",opts:["Como","Porque","Pero","Sin embargo"],ans:"Como",hint:"You need a causal connector that works at the beginning of a sentence."},
        {type:"fb",opts:["Puesto que","Sin embargo","Mientras que","En cambio"],hint:"You need a formal 'since/given that' to state the reason first.",s:"{1} todos estan de acuerdo, podemos continuar.",a:["Puesto que"]},
        {type:"mc",q:"Which sentence is grammatically INCORRECT?",opts:["Como hace frio, vamos al cine.","Vamos al cine como hace frio.","Ya que hace frio, vamos al cine.","Dado que hace frio, vamos al cine."],ans:"Vamos al cine como hace frio.",hint:"One of these connectors can ONLY appear at the start of the sentence."},
        {type:"drag_fill",hint:"A formal reason at the start, followed by the logical obligation.",s:"{1} el vuelo sale temprano, {2} preparar las maletas esta noche.",blanks:{"1":"Dado que","2":"debemos"},pool:["Dado que","debemos","Sin embargo","podemos","Mientras que","queremos"]},
        {type:"match",pairs:[
          {trg:"porque",src:"because (informal)"},
          {trg:"como",src:"since (sentence start only)"},
          {trg:"ya que",src:"since (semi-formal)"},
          {trg:"puesto que",src:"since/given that (formal)"},
          {trg:"dado que",src:"given that (very formal)"}
        ]},
        {type:"mc",q:"In a business report, which connector is most appropriate? '_____ los resultados son positivos, recomendamos continuar.'",opts:["Porque","Como","Dado que","Pero"],ans:"Dado que",hint:"Business reports call for the most formal register."},
        {type:"fb",opts:["Ya que","Dado que","Sin embargo","Aunque"],hint:"A semi-formal 'since' works naturally in this conversational advice.",s:"{1} tienes experiencia, ¿por que no solicitas el puesto?",a:["Ya que"]},
        {type:"mc",q:"'Como _____ lloviendo, nos quedamos en casa.' Fill in with the correct verb form.",opts:["estuviera","este","estaba","esta"],ans:"esta",hint:"Como introduces a factual cause. The rain is happening now."},
        {type:"drag_fill",hint:"Two causal connectors of similar formality introducing two reasons.",s:"{1} la reunion es a las tres, y {2} todos han confirmado, empezaremos puntualmente.",blanks:{"1":"Dado que","2":"ya que"},pool:["Dado que","ya que","sin embargo","porque","aunque","mientras que"]},
        {type:"fb",opts:["Puesto que","Sin embargo","En cambio","Aunque"],hint:"A formal meeting closure needs a formal causal connector.",s:"{1} no hay mas preguntas, damos por terminada la reunion.",a:["Puesto que"]},
        {type:"mc",q:"Which cause connector can ONLY be used at the beginning of a sentence?",opts:["Como","Ya que","Puesto que","Dado que"],ans:"Como",hint:"Three of these can go at the beginning or middle. One is restricted to the start."},
        {type:"drag_fill",hint:"Two causal connectors. The first one must start the sentence.",s:"{1} hace buen tiempo y {2} es fin de semana, vamos a la montana.",blanks:{"1":"Como","2":"ya que"},pool:["Como","ya que","sin embargo","aunque","por eso","en cambio"]}
  ]},
  {id:"esp23l5",title:"Por lo tanto...",icon:"➡️",xp:20,board:true,steps:[
        {type:"intro",title:"Por lo tanto...",desc:"Learn to express consequences and conclusions with formal connectors: por lo tanto, por eso, asi que, de modo que, por consiguiente.",goals:["Use por lo tanto and por consiguiente for 'therefore'","Use asi que for 'so' in everyday speech","Use de modo que for 'so that/in such a way that'"]},
        {type:"teach",trg:"por lo tanto",src:"therefore, consequently",pos:"conj",gender:null,phonetic:"pohr loh TAHN-toh",note:"Formal connector for logical conclusions.\nCommon in arguments, reports, and debates.",example:"A: No hemos recibido el pago.\nB: Por lo tanto, no podemos enviar el pedido.\nA: Entiendo. El cliente tiene un retraso.\nB: Por lo tanto, debemos esperar.\nA: Informare al equipo.",exampleSrc:"A: We haven't received the payment.\nB: Therefore, we can't send the order.\nA: I understand. The client has a delay.\nB: Therefore, we must wait.\nA: I'll inform the team.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"teach",trg:"por eso",src:"that's why, for that reason",pos:"conj",gender:null,phonetic:"pohr EH-soh",note:"The most common consequence connector in speech.\nLess formal than por lo tanto.",example:"A: Ayer llovi mucho.\nB: Por eso las calles estan mojadas.\nA: Y por eso hay tanto trafico.\nB: Por eso sali temprano de casa.\nA: Buena decision. Yo por eso vine en metro.",exampleSrc:"A: It rained a lot yesterday.\nB: That's why the streets are wet.\nA: And that's why there's so much traffic.\nB: That's why I left home early.\nA: Good decision. That's why I came by metro.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"teach",trg:"asi que",src:"so, therefore",pos:"intj",gender:null,phonetic:"ah-SEE keh",note:"Everyday 'so'. Very common in conversation.\nConnects cause and effect naturally.",example:"A: No tengo coche.\nB: Asi que vas en autobus.\nA: Si. Tardo una hora, asi que salgo pronto.\nB: Es mucho tiempo. Asi que no puedes dormir hasta tarde.\nA: Exacto, asi que me acuesto temprano.",exampleSrc:"A: I don't have a car.\nB: So you go by bus.\nA: Yes. It takes an hour, so I leave early.\nB: That's a lot of time. So you can't sleep in.\nA: Exactly, so I go to bed early.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"de modo que",src:"so that, in such a way that",pos:"noun",gender:null,phonetic:"deh MOH-doh keh",note:"Can express purpose (so that) or result (so).\nMore formal than asi que.",example:"A: Organice todo bien, de modo que no hubiera problemas.\nB: Buena planificacion.\nA: Prepare los documentos, de modo que todo estuviera listo.\nB: De modo que la presentacion fue un exito.\nA: Exacto. La preparacion es clave.",exampleSrc:"A: I organized everything well, so that there wouldn't be problems.\nB: Good planning.\nA: I prepared the documents, so that everything would be ready.\nB: So the presentation was a success.\nA: Exactly. Preparation is key.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"por consiguiente",src:"consequently, as a result",pos:"intj",gender:null,phonetic:"pohr kohn-see-GYEHN-teh",note:"Very formal. Used in academic and business writing.\nSimilar to por lo tanto but more elevated.",example:"A: La empresa ha perdido clientes.\nB: Por consiguiente, los ingresos han bajado.\nA: Por consiguiente, debemos reducir gastos.\nB: Es una situacion dificil. Por consiguiente, hay que actuar rapido.\nA: Propongo una reunion urgente.",exampleSrc:"A: The company has lost clients.\nB: Consequently, revenues have dropped.\nA: Consequently, we must reduce expenses.\nB: It's a difficult situation. Consequently, we need to act fast.\nA: I propose an urgent meeting.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Consequence Connectors: Formality Scale",deepDive:"A subtle distinction: 'por eso' looks backward (explains WHY something happened), while 'por lo tanto' looks forward (draws a CONCLUSION from evidence). 'Llueve, por eso me quedo' (it's raining, that's why I stay) vs 'Llueve, por lo tanto cancelamos' (it's raining, therefore we cancel).",text:"From informal to formal:\n1. Asi que (so) = everyday conversation\n2. Por eso (that's why) = everyday, explains reasons\n3. De modo que (so that) = semi-formal, result/purpose\n4. Por lo tanto (therefore) = formal arguments\n5. Por consiguiente (consequently) = very formal, academic"},
        {type:"mc",q:"'Estoy enfermo. _____ no puedo ir a trabajar.' Which is most natural in a casual conversation?",opts:["Asi que","Por consiguiente","De modo que","Por lo tanto"],ans:"Asi que",hint:"Casual conversation calls for the informal conse___nce connector."},
        {type:"fb",opts:["Por eso","Aunque","Sin embargo","Mientras que"],hint:"You're explaining WHY the river is swollen. A common consequence connector.",s:"Ha llovido mucho. {1} el rio esta crecido.",a:["Por eso"]},
        {type:"mc",q:"In a formal business email: 'No hemos cumplido los objetivos. _____, debemos revisar la estrategia.'",opts:["Asi que","Por lo tanto","Por eso","Pero"],ans:"Por lo tanto",hint:"A business email requires a formal logical connector."},
        {type:"drag_fill",hint:"First: casual consequence. Second: formal conclusion about the retake.",s:"No estudie, {1} suspendi el examen. {2}, tuve que repetirlo.",blanks:{"1":"asi que","2":"Por lo tanto"},pool:["asi que","Por lo tanto","sin embargo","aunque","mientras que","en cambio"]},
        {type:"match",pairs:[
          {trg:"asi que",src:"so (informal)"},
          {trg:"por eso",src:"that's why"},
          {trg:"de modo que",src:"so that / in such a way"},
          {trg:"por lo tanto",src:"therefore"},
          {trg:"por consiguiente",src:"consequently (very formal)"}
        ]},
        {type:"mc",q:"'Trabaje mucho, _____ todo salio perfecto.' Which connector expresses the result?",opts:["aunque","sin embargo","de modo que","mientras que"],ans:"de modo que",hint:"The hard work led to the perfect result. You need a result connector."},
        {type:"fb",opts:["Por consiguiente","Asi que","En cambio","Mientras que"],hint:"A grave situation in formal context calls for the most formal connector.",s:"La situacion es grave. {1}, debemos tomar medidas urgentes.",a:["Por consiguiente"]},
        {type:"drag_fill",hint:"First: casual consequence of no direct flights. Second: formal conclusion.",s:"No hay vuelos directos, {1} tenemos que hacer escala. {2} el viaje sera mas largo.",blanks:{"1":"asi que","2":"Por lo tanto"},pool:["asi que","Por lo tanto","sin embargo","aunque","dado que","en cambio"]},
        {type:"mc",q:"Which sentence uses a consequence connector INCORRECTLY?",opts:["Llueve, por eso me quedo.","Llueve, por lo tanto me quedo.","Llueve, asi que me quedo.","Aunque llueve, por lo tanto me quedo."],ans:"Aunque llueve, por lo tanto me quedo.",hint:"Mixing a concession connector with a consequence connector creates a contradiction."},
        {type:"fb",opts:["Por eso","Aunque","Sin embargo","En cambio"],hint:"The passing grades explain the teacher's happiness.",s:"Todos aprobaron el examen. {1} la profesora esta muy contenta.",a:["Por eso"]},
        {type:"mc",q:"'No tengo paraguas, _____ me he mojado.' Which consequence connector is most natural in casual speech?",opts:["asi que","por consiguiente","de modo que","por lo tanto"],ans:"asi que",hint:"A simple everyday conse___nce in casual conversation."}
  ]},
  {id:"esp23l6",title:"A menos que...",icon:"🔐",xp:20,board:true,steps:[
        {type:"intro",title:"A menos que...",desc:"Learn conditional connectors that ALWAYS require the subjunctive: a menos que, con tal de que, siempre que, a condicion de que.",goals:["Use a menos que (unless) + subjunctive","Use con tal de que (provided that) + subjunctive","Use siempre que (as long as) + subjunctive for conditions"]},
        {type:"teach",trg:"a menos que",src:"unless",pos:"intj",gender:null,phonetic:"ah MEH-nohs keh",note:"ALWAYS followed by subjunctive.\nThe exception condition is always uncertain.",example:"A: ¿Vamos a la playa manana?\nB: Si, a menos que llueva.\nA: Y si llueve, ¿que hacemos?\nB: Vamos al cine, a menos que prefieras quedarte en casa.\nA: No, a menos que este muy cansada, salgo.",exampleSrc:"A: Shall we go to the beach tomorrow?\nB: Yes, unless it rains.\nA: And if it rains, what do we do?\nB: We go to the cinema, unless you prefer to stay home.\nA: No, unless I'm very tired, I'll go out.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"con tal de que",src:"provided that, as long as",pos:"intj",gender:null,phonetic:"kohn tahl deh keh",note:"ALWAYS + subjunctive. Sets a condition for permission.\nCon tal de que = 'on the condition that'.",example:"A: Puedes usar mi coche.\nB: ¿De verdad? Muchas gracias.\nA: Con tal de que lo devuelvas con gasolina.\nB: Por supuesto. Con tal de que me digas donde esta el parking.\nA: Esta en la calle principal. Con tal de que conduzcas con cuidado, no hay problema.",exampleSrc:"A: You can use my car.\nB: Really? Thank you very much.\nA: Provided that you return it with gas.\nB: Of course. As long as you tell me where the parking is.\nA: It's on the main street. As long as you drive carefully, no problem.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"siempre que",src:"as long as, provided that",pos:"intj",gender:null,phonetic:"SYEHM-preh keh",note:"ALWAYS + subjunctive when expressing a condition.\nNote: siempre que + indicative = 'whenever' (different meaning).",example:"A: ¿Puedo trabajar desde casa?\nB: Siempre que cumplas con tus tareas, si.\nA: Perfecto. ¿Y puedo elegir mi horario?\nB: Siempre que estes disponible para reuniones.\nA: Entendido. Siempre que haya internet, puedo trabajar desde cualquier sitio.",exampleSrc:"A: Can I work from home?\nB: As long as you complete your tasks, yes.\nA: Perfect. And can I choose my schedule?\nB: As long as you're available for meetings.\nA: Understood. As long as there's internet, I can work from anywhere.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"a condicion de que",src:"on the condition that",pos:"conj",gender:null,phonetic:"ah kohn-dee-SYOHN deh keh",note:"Very formal conditional connector.\nALWAYS followed by subjunctive.",example:"A: Te presto el dinero.\nB: Gracias. ¿Cual es la condicion?\nA: A condicion de que me lo devuelvas en un mes.\nB: De acuerdo. A condicion de que no me cobres intereses.\nA: Trato hecho. A condicion de que cumplas tu palabra.",exampleSrc:"A: I'll lend you the money.\nB: Thanks. What's the condition?\nA: On the condition that you return it in a month.\nB: Agreed. On the condition that you don't charge me interest.\nA: Deal. On the condition that you keep your word.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"tip",title:"Conditional Connectors + Subjunctive",deepDive:"Compare with 'si' (if): 'Si llueve, me quedo' uses indicative because si + present is a real possibility pattern. But 'a menos que llueva' uses subjunctive because 'unless' frames the condition as an exception to the default plan. The uncertainty is built into the connector's meaning.",text:"These connectors ALWAYS require subjunctive:\n\n1. A menos que = unless\n2. Con tal de que = provided that\n3. Siempre que = as long as (conditional)\n4. A condicion de que = on the condition that\n\nWhy? Because the condition is always UNCERTAIN.\nYou don't know if it will be fulfilled."},
        {type:"mc",q:"'No voy a la fiesta, a menos que me _____ .' Choose the correct subjunctive form of 'invite'.",opts:["inviten","invitan","invitaron","invitaran"],ans:"inviten",hint:"A menos que always triggers the present subjunctive for current/future conditions."},
        {type:"fb",opts:["hagas","haces","hiciste","harias"],hint:"The condition (doing homework) is uncertain. Use present subjunctive.",s:"Puedes salir con tal de que {1} los deberes.",a:["hagas"]},
        {type:"mc",q:"'Siempre que _____ a tiempo, puedes venir.' Fill in with 'arrive' in subjunctive.",opts:["llegas","llegues","llegaste","llegarias"],ans:"llegues",hint:"The condition of arriving on time is uncertain. Subjunctive required."},
        {type:"drag_fill",hint:"Both conditions require present subjunctive after a condicion de que.",s:"Te ayudo a condicion de que me {1} la verdad y no me {2}.",blanks:{"1":"digas","2":"mientas"},pool:["digas","mientas","dices","mientes","dijeras","mintieras"]},
        {type:"mc",q:"Which sentence is CORRECT?",opts:["No ire a menos que me acompanaste.","No ire a menos que me acompanas.","No ire a menos que me acompanes.","No ire a menos que me acompanarias."],ans:"No ire a menos que me acompanes.",hint:"A ___ ___ ALWAYS requ___s the subjunctive mood."},
        {type:"fb",opts:["haya","hay","habia","habria"],hint:"The existence of another option is uncertain. Subjunctive of haber.",s:"A menos que {1} otro remedio, seguiremos con el plan original.",a:["haya"]},
        {type:"match",pairs:[
          {trg:"a menos que llueva",src:"unless it rains"},
          {trg:"con tal de que estudies",src:"provided that you study"},
          {trg:"siempre que vengas",src:"as long as you come"},
          {trg:"a condicion de que pagues",src:"on the condition that you pay"}
        ]},
        {type:"drag_fill",hint:"Both conditions after siempre que need present subjunctive.",s:"Acepto el trabajo siempre que el salario {1} bueno y que {2} vacaciones.",blanks:{"1":"sea","2":"haya"},pool:["sea","haya","es","hay","seria","habria"]},
        {type:"mc",q:"'Con tal de que _____ contentos, yo estoy feliz.' (they are happy, uncertain)",opts:["estuvieran","estan","estaban","esten"],ans:"esten",hint:"Con tal de que triggers subjunctive. Present subjunctive of estar."},
        {type:"fb",opts:["prometas","prometes","prometiste","prometias"],hint:"The promise hasn't been made yet. Use subjunctive after a menos que.",s:"No te lo digo a menos que me {1} que no se lo diras a nadie.",a:["prometas"]},
        {type:"mc",q:"'Puedes quedarte siempre que _____ las reglas de la casa.' Fill in with 'respect'.",opts:["respetes","respetas","respetaste","respetarias"],ans:"respetes",hint:"Siempre que as a condition requires subjunctive."},
        {type:"drag_fill",hint:"Both conditions are uncertain. Present subjunctive after both connectors.",s:"No saldremos a menos que {1} de llover, con tal de que el parque {2} abierto.",blanks:{"1":"pare","2":"este"},pool:["pare","este","para","esta","parara","estuviera"]}
  ]},
  {id:"esp23l7",title:"Por un lado...",icon:"💬",xp:20,board:true,steps:[
        {type:"intro",title:"Por un lado...",desc:"Build complex arguments by combining multiple connectors. Learn to present balanced viewpoints using por un lado...por otro lado and layered reasoning.",goals:["Use por un lado...por otro lado for balanced arguments","Combine cause, contrast, and consequence connectors","Structure multi-sentence arguments with connector variety"]},
        {type:"teach",trg:"por un lado...por otro lado",src:"on one hand...on the other hand",pos:"intj",gender:null,phonetic:"pohr oon LAH-doh...pohr OH-troh LAH-doh",note:"The classic structure for balanced arguments.\nPresents two sides before reaching a conclusion.",example:"A: ¿Que opinas del teletrabajo?\nB: Por un lado, es comodo. Por otro lado, es solitario.\nA: Entiendo. Por un lado, ahorras tiempo. Por otro lado, pierdes contacto.\nB: Exacto. Es una cuestion de equilibrio.\nA: Por un lado me gusta, por otro lo echo de menos.",exampleSrc:"A: What do you think about remote work?\nB: On one hand, it's comfortable. On the other hand, it's lonely.\nA: I see. On one hand, you save time. On the other hand, you lose contact.\nB: Exactly. It's a question of balance.\nA: On one hand I like it, on the other I miss it.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"en primer lugar...en segundo lugar",src:"firstly...secondly",pos:"intj",gender:null,phonetic:"ehn pree-MEHR loo-GAHR...ehn seh-GOON-doh loo-GAHR",note:"Used to enumerate reasons in a structured argument.\nCan extend to en tercer lugar, en cuarto lugar...",example:"A: ¿Por que debemos cambiar de estrategia?\nB: En primer lugar, los resultados son malos.\nA: ¿Y en segundo lugar?\nB: En segundo lugar, la competencia nos esta superando.\nA: Son argumentos solidos. En tercer lugar, los clientes se quejan.",exampleSrc:"A: Why should we change strategy?\nB: Firstly, the results are bad.\nA: And secondly?\nB: Secondly, the competition is overtaking us.\nA: Those are solid arguments. Thirdly, customers are complaining.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Building Multi-Connector Arguments",deepDive:"Native speakers rarely use the same connector twice in a paragraph. Varying your connectors shows linguistic sophistication. Instead of 'sin embargo...sin embargo...sin embargo,' use 'sin embargo...no obstante...a pesar de ello.' This variety is a marker of B1+ proficiency.",text:"A strong argument combines connectors:\n\n1. INTRODUCE: En primer lugar / Por un lado\n2. ADD CAUSE: Ya que / Puesto que / Dado que\n3. ADD CONTRAST: Sin embargo / No obstante\n4. ADD CONSEQUENCE: Por lo tanto / Por consiguiente\n5. CONCLUDE: En conclusion / En resumen\n\nExample flow:\nPor un lado, X. Ya que Y, Z.\nSin embargo, W. Por lo tanto, V."},
        {type:"mc",q:"Complete the argument: 'Por un lado, el proyecto es interesante. _____, requiere mucho tiempo.'",opts:["Por otro lado","Por lo tanto","Ya que","Asi que"],ans:"Por otro lado",hint:"You started with 'por un ___,' so the matching pair is needed."},
        {type:"fb",opts:["En segundo lugar","Sin embargo","Por eso","Aunque"],hint:"You're listing the second reason in an enumerated argument.",s:"En primer lugar, necesitamos mas personal. {1}, debemos mejorar la tecnologia.",a:["En segundo lugar"]},
        {type:"teach",trg:"en conclusion",src:"in conclusion",pos:"intj",gender:null,phonetic:"ehn kohn-kloo-SYOHN",note:"Used to wrap up an argument or presentation.\nSimilar: en resumen (in summary).",example:"A: Hemos analizado todos los datos.\nB: En conclusion, debemos actuar rapido.\nA: Estoy de acuerdo. En resumen, la situacion es urgente.\nB: En conclusion, propongo una reunion extraordinaria.\nA: Aprobado. Convoquemos para manana.",exampleSrc:"A: We've analyzed all the data.\nB: In conclusion, we must act quickly.\nA: I agree. In summary, the situation is urgent.\nB: In conclusion, I propose an extraordinary meeting.\nA: Approved. Let's call it for tomorrow.",funFact:"Cognate with English 'in conclusion'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"en resumen",src:"in summary, to sum up",pos:"intj",gender:null,phonetic:"ehn reh-SOO-mehn",note:"Condenses the main points of a discussion.\nOften used at the end of meetings or essays.",example:"A: Hemos hablado de muchos temas hoy.\nB: En resumen, tenemos tres prioridades.\nA: ¿Cuales son?\nB: En resumen: mejorar ventas, reducir costes y contratar personal.\nA: En resumen, mucho trabajo por delante.",exampleSrc:"A: We've talked about many topics today.\nB: In summary, we have three priorities.\nA: What are they?\nB: In summary: improve sales, reduce costs, and hire staff.\nA: In summary, a lot of work ahead.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"drag_fill",hint:"First: the contrasting side. Second: the logical conclusion drawn from both.",s:"Por un lado, el sueldo es bueno. {1}, el horario es terrible. {2}, debemos negociar mejores condiciones.",blanks:{"1":"Por otro lado","2":"Por lo tanto"},pool:["Por otro lado","Por lo tanto","En cambio","Ya que","Aunque","Asi que"]},
        {type:"mc",q:"Which is the best order for a formal argument paragraph?",opts:["Por lo tanto X. Sin embargo Y. Dado que Z.","Dado que X, Y. Sin embargo, Z. Por lo tanto, W.","Sin embargo X. Por lo tanto Y. Dado que Z.","Asi que X. Porque Y. Pero Z."],ans:"Dado que X, Y. Sin embargo, Z. Por lo tanto, W.",hint:"A logical argument flows: cause, contrast, then conclusion."},
        {type:"fb",opts:["Por un lado","Por lo tanto","En conclusion","Ya que"],hint:"You're introducing the first of two contrasting points about the business.",s:"{1}, hemos mejorado las ventas. Sin embargo, los gastos siguen altos.",a:["Por un lado"]},
        {type:"drag_fill",hint:"An enumerated argument with two points and a conclusion.",s:"{1} lugar, la educacion es fundamental. {2} lugar, la sanidad necesita mas inversion. {3}, debemos aumentar el presupuesto.",blanks:{"1":"En primer","2":"En segundo","3":"En conclusion"},pool:["En primer","En segundo","En conclusion","Sin embargo","Por eso","Mientras que"]},
        {type:"match",pairs:[{trg:"por un lado...por otro lado",src:"on one hand...on the other"},{trg:"en primer lugar",src:"firstly"},{trg:"en conclusion",src:"in conclusion"},{trg:"en resumen",src:"in summary"}]},
        {type:"mc",q:"Fill in: 'Ya que los datos son claros, y _____ que los expertos coinciden, debemos actuar.'",opts:["aunque","sin embargo","dado","por eso"],ans:"dado",hint:"You need a second causal connector to reinforce the first reason."},
        {type:"fb",opts:["En conclusion","Sin embargo","Por un lado","Ya que"],hint:"You're wrapping up a speech with a final statement.",s:"{1}, quiero agradecer a todos por su trabajo y su dedicacion.",a:["En conclusion"]},
        {type:"drag_fill",hint:"Two formal causes lead to a formal consequence.",s:"{1} el problema es grave, y {2} no hemos encontrado solucion, {3} debemos pedir ayuda externa.",blanks:{"1":"Dado que","2":"puesto que","3":"por lo tanto"},pool:["Dado que","puesto que","por lo tanto","sin embargo","aunque","en cambio"]},
        {type:"mc",q:"Which connector pair would you use to present a BALANCED argument before concluding?",opts:["Asi que...asi que...asi que","Sin embargo...sin embargo...sin embargo","Porque...porque...porque","Por un lado...por otro lado...en conclusion"],ans:"Por un lado...por otro lado...en conclusion",hint:"A balanced argument presents both sides, then draws a ___."},
        {type:"fb",opts:["Por otro lado","Por lo tanto","Ya que","Asi que"],hint:"You started with 'por un ___,' so the matching contrasting side is needed.",s:"Por un lado, el teletrabajo ahorra tiempo. {1}, puede ser solitario.",a:["Por otro lado"]}
  ]},
  {id:"esp23l8",title:"Conectando ideas",icon:"🧩",xp:25,board:true,steps:[
        {type:"intro",title:"Conectando ideas",desc:"Review and practice all the connectors from this unit. Choose the right connector for each context, rewrite sentences, and build complete arguments.",goals:["Choose the correct connector type for each context","Distinguish between similar connectors","Build multi-connector arguments fluently"]},
        {type:"tip",title:"Connector Map: Full Review",deepDive:"Mastering connectors is one of the clearest markers of B1+ proficiency. Native speakers use them constantly to structure their speech and writing. The key is not just knowing them but choosing the right one for your formality level and logical purpose.",text:"CONTRAST: aunque, sin embargo, no obstante, en cambio, mientras que, por el contrario\nCAUSE: porque, como, ya que, puesto que, dado que\nCONSEQUENCE: asi que, por eso, de modo que, por lo tanto, por consiguiente\nCONDITION + SUBJ: a menos que, con tal de que, siempre que, a condicion de que\nSTRUCTURE: por un lado...por otro lado, en primer lugar, en conclusion, en resumen"},
        {type:"mc",q:"'El hotel era caro. _____, la ubicacion era perfecta.' Choose the best connector.",opts:["Sin embargo","Por eso","Ya que","Asi que"],ans:"Sin embargo",hint:"Price vs location is a contrast. You need 'however'."},
        {type:"fb",opts:["a menos que","sin embargo","por lo tanto","ya que"],hint:"You need 'unless' followed by subjunctive.",s:"No ire a la reunion {1} me inviten personalmente.",a:["a menos que"]},
        {type:"mc",q:"'_____ el tiempo esta malo, nos quedamos en casa. _____, podemos ver una pelicula.' Fill in both gaps.",opts:["Sin embargo / Ya que","Como / Asi que","Aunque / Por eso","A menos que / En cambio"],ans:"Como / Asi que",hint:"First: cause at the start of sentence. Second: casual conse___nce."},
        {type:"drag_fill",hint:"Two-sided argument leading to a conclusion about moving.",s:"Por un lado, me gusta vivir en la ciudad. {1}, echo de menos la naturaleza. {2}, estoy pensando en mudarme al campo.",blanks:{"1":"Por otro lado","2":"Por lo tanto"},pool:["Por otro lado","Por lo tanto","Ya que","Mientras que","A menos que","Sin embargo"]},
        {type:"mc",q:"In a job interview, which is the most appropriate? 'He trabajado mucho. _____, tengo mucha experiencia.'",opts:["Por eso","Asi que","Por consiguiente","Pero"],ans:"Por consiguiente",hint:"A formal consequence connector suits a professional context."},
        {type:"fb",opts:["Aunque","Sin embargo","Por eso","Ya que"],hint:"You're conceding a hypothetical (rain) but going anyway. Subjunctive follows.",s:"{1} llueva, iremos de excursion. Llevamos paraguas.",a:["Aunque"]},
        {type:"drag_fill",hint:"Two formal causal connectors reinforcing the reason to protest.",s:"{1} que los precios han subido, {2} que el salario no ha cambiado, debemos protestar.",blanks:{"1":"Dado","2":"y ya"},pool:["Dado","y ya","sin embargo","aunque","por eso","asi que"]},
        {type:"mc",q:"Which sentence correctly uses 'mientras que' for comparison?",opts:["El cine es bueno mientras que.","Mientras que llueve, me quedo en casa.","Mientras que, sin embargo, no obstante.","Maria prefiere el cine, mientras que Juan prefiere el teatro."],ans:"Maria prefiere el cine, mientras que Juan prefiere el teatro.",hint:"___ ___ compares two parallel but contrasting situations."},
        {type:"match",pairs:[
          {trg:"aunque + indicative",src:"even though (fact)"},
          {trg:"aunque + subjunctive",src:"even if (hypothetical)"},
          {trg:"a menos que + subjunctive",src:"unless"},
          {trg:"con tal de que + subjunctive",src:"provided that"},
          {trg:"siempre que + subjunctive",src:"as long as (condition)"}
        ]},
        {type:"fb",opts:["completo","completara","complete","completaria"],hint:"The team DID complete it. Indicative past tense for a real achievement.",s:"No obstante los problemas, el equipo {1} con exito el proyecto.",a:["completo"]},
        {type:"mc",q:"'_____ la economia, _____ el desempleo. Sin embargo, hay esperanza.' Fill in two cause-effect blanks.",opts:["Dado que...mejora, por lo tanto...baja","Aunque...mejora, sin embargo...baja","Mientras que...mejora, en cambio...baja","A menos que...mejore, por eso...baja"],ans:"Dado que...mejora, por lo tanto...baja",hint:"You need a cause and its logical conse___nce before the contrast."},
        {type:"drag_fill",hint:"All three structural markers start with the same word.",s:"{1} primer lugar, necesitamos mejorar la comunicacion. {2} segundo lugar, debemos invertir en formacion. {3} conclusion, el cambio es necesario.",blanks:{"1":"En","2":"En","3":"En"},pool:["En","En","En","Por","Sin","De"]},
        {type:"mc",q:"Choose the INCORRECT sentence:",opts:["Como hace sol, vamos al parque.","Vamos al parque como hace sol.","Ya que hace sol, vamos al parque.","Dado que hace sol, vamos al parque."],ans:"Vamos al parque como hace sol.",hint:"One of these causal connectors can ONLY start the sentence, never go in the middle."},
        {type:"fb",opts:["creo","crea","creyera","creeria"],hint:"Stating your belief as fact in a conclusion. Use indicative present.",s:"En resumen, aunque el camino es dificil, {1} que con esfuerzo todo es posible.",a:["creo"]},
        {type:"drag_fill",hint:"Two formal causes (given that / since) leading to a formal conclusion (therefore).",s:"{1} que el proyecto es ambicioso, y {2} que no tenemos mucho presupuesto, {3} debemos buscar financiacion externa.",blanks:{"1":"Dado","2":"ya","3":"por lo tanto"},pool:["Dado","ya","por lo tanto","sin embargo","aunque","en cambio"]},
        {type:"mc",q:"What is the function of 'en resumen' in an argument?",opts:["To express a cause","To introduce a new contrasting idea","To summarize the main points at the end","To state a condition"],ans:"To summarize the main points at the end",hint:"Think about where in an argument you would use 'in summary'."}
  ]}
]};
